-- Program: Wedding Ready Shred
-- Category: Fat Loss -> fat_loss
-- Priority: High
-- Durations: [4, 6, 8, 12], Sessions: [5, 5, 6, 6]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Wedding Ready Shred',
    'A comprehensive body transformation program for brides and grooms. Emphasizes posture, toned arms, sculpted legs, and a flat midsection. Includes HIIT for fat loss and targeted isolation work for photo-ready definition.',
    'fat_loss',
    'all_levels',
    12,
    6,
    'full_body',
    ARRAY['Maximize muscle hypertrophy', 'Time under tension', 'Maximize calorie burn', 'Preserve lean muscle']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Wedding Ready Shred - 4w 5x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    4,
    'Wedding Ready Shred - 4w 5x/wk',
    'fat_loss',
    5,
    60,
    ARRAY['Maximize muscle hypertrophy', 'Time under tension', 'Maximize calorie burn', 'Preserve lean muscle']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Wedding Ready Shred'
ON CONFLICT DO NOTHING;

